const raw = $input.first().json;
const item = raw.body ?? raw;
const now = new Date().toISOString();
const project_id = (item.project_id || '').trim() || ('proj_' + (Math.random().toString(36).slice(2,10)+Date.now().toString(36)));
const title = (item.title || 'Untitled Project').replace(/'/g, "''");
const run_id = 'run_' + (Math.random().toString(36).slice(2,10)+Date.now().toString(36));
return [{ json: { project_id, title, run_id, now } }];

const prep = $('Code - Prepare Create Resume').first().json;
const runRow = $('Postgres - Insert Run').first().json;
const proj = $('Postgres - Link Run To Project').first().json;
const reused = runRow.reused === true || runRow.reused === 't';
return [{ json: {
  success: true,
  message: reused ? 'Existing run resumed.' : 'Project resumed.',
  data: {
    project_id: proj.project_id || prep.project_id,
    run_id: runRow.actual_run_id || prep.run_id,
    reused_run: reused,
    status: proj.status || 'active',
    current_step: proj.current_step || null,
    last_completed_step: proj.last_completed_step || null,
    next_action: proj.next_action || 'start',
    last_summary: proj.last_summary || null
  }
} }];

const raw = $input.first().json;
const item = raw.body ?? raw;
if (!item.project_id) return [{ json: { success: false, message: 'Validation failed', data: { error: 'invalid_input', details: 'Missing required field: project_id' } } }];
return [{ json: { project_id: item.project_id } }];

const row = $input.first().json;
if (!row || !row.project_id) return [{ json: { success: false, message: 'Project not found.', data: { error: 'No project for this project_id' } } }];
return [{ json: { success: true, message: 'State loaded.', data: {
  project_id: row.project_id, title: row.title, status: row.status,
  latest_run_id: row.latest_run_id, current_step: row.current_step,
  last_completed_step: row.last_completed_step, next_action: row.next_action,
  last_summary: row.last_summary, created_at: row.created_at, updated_at: row.updated_at,
  run: row.r_run_id ? { run_id: row.r_run_id, status: row.r_status, current_step: row.r_current_step, last_completed_step: row.r_last_completed, next_action: row.r_next_action, retry_count: row.retry_count, error: row.r_error, started_at: row.started_at, completed_at: row.completed_at } : null
} } }];

const raw = $input.first().json;
const item = raw.body ?? raw;
if (!item.project_id || !item.run_id || !item.step_name) {
  return [{ json: { success: false, message: 'Validation failed', data: { error: 'invalid_input', details: 'Missing required fields: project_id, run_id, step_name' } } }];
}
const step_result_id = 'sr_' + (Math.random().toString(36).slice(2,10)+Date.now().toString(36));
const log_id = 'log_' + (Math.random().toString(36).slice(2,10)+Date.now().toString(36));
const now = new Date().toISOString();
const status = item.status || 'success';
const summary = (item.summary || '').replace(/'/g, "''").slice(0, 2000);
const structured_output = JSON.stringify(item.structured_output || {});
const risks = JSON.stringify(item.risks || []);
const assumptions = JSON.stringify(item.assumptions || []);
const blocking_questions = JSON.stringify(item.blocking_questions || []);
return [{ json: { project_id: item.project_id, run_id: item.run_id, step_name: item.step_name, step_result_id, log_id, now, status, summary, structured_output, risks, assumptions, blocking_questions } }];

const prep = $('Code - Prepare Save Step').first().json;
const proj = $('Postgres - Update Project State').first().json;
const insertResult = $('Postgres - Insert Step Result').first().json;
return [{ json: { success: true, message: 'Step result saved.', data: {
  project_id: prep.project_id, run_id: (insertResult && insertResult.run_id) || prep.run_id,
  step_name: prep.step_name, step_result_id: prep.step_result_id,
  status: prep.status, project_status: (proj && proj.status) || 'active',
  next_action: (proj && proj.next_action) || 'continue'
} } }];

const raw = $input.first().json;
const item = raw.body ?? raw;
if (!item.project_id || !item.run_id || !item.step_name) {
  return [{ json: { success: false, message: 'Validation failed', data: { error: 'invalid_input', details: 'Missing required fields: project_id, run_id, step_name' } } }];
}
const log_id = 'log_' + (Math.random().toString(36).slice(2,10)+Date.now().toString(36));
const now = new Date().toISOString();
const retry_count = Number(item.retry_count) || 0;
const next_action = item.next_action || 'stop';
const error_msg = (item.error || 'Unknown error').replace(/'/g, "''").slice(0, 1000);
return [{ json: { project_id: item.project_id, run_id: item.run_id, step_name: item.step_name, error_msg, retry_count, next_action, run_status: 'failed', log_id, now } }];

const prep = $('Code - Prepare Mark Failed').first().json;
const proj = $('Postgres - Update Project Failed').first().json;
return [{ json: { success: true, message: 'Failure recorded.', data: {
  project_id: prep.project_id, run_id: prep.run_id, step_name: prep.step_name,
  status: prep.run_status, error: prep.error_msg,
  retry_count: prep.retry_count, next_action: (proj && proj.next_action) || prep.next_action
} } }];

const raw = $input.first().json;
const item = raw.body ?? raw;
if (!item.project_id) return [{ json: { success: false, message: 'Validation failed', data: { error: 'invalid_input', details: 'Missing required field: project_id' } } }];
return [{ json: { project_id: item.project_id } }];

const row = $input.first().json;
if (!row || !row.project_id) return [{ json: { success: false, message: 'Project not found.', data: { error: 'No project found' } } }];
return [{ json: { success: true, message: 'Next step retrieved.', data: {
  project_id: row.project_id, status: row.status,
  current_step: row.current_step, last_completed_step: row.last_completed_step,
  next_action: row.r_next_action || row.next_action || 'start',
  run_id: row.latest_run_id, run_status: row.r_status,
  error: row.error || null, retry_count: row.retry_count || 0
} } }];

const raw = $input.first().json;
const item = raw.body ?? raw;
if (!item.project_id) return [{ json: { success: false, message: 'Validation failed', data: { error: 'invalid_input', details: 'Missing required field: project_id' } } }];
return [{ json: { project_id: item.project_id } }];

const row = $input.first().json;
if (!row || !row.project_id) return [{ json: { success: false, message: 'Project not found.', data: { error: 'No project found' } } }];
return [{ json: {
  success: true,
  message: 'Snapshot loaded.',
  data: {
    project_id: row.project_id,
    run_id: row.latest_run_id || null,
    current_step: row.current_step || null,
    last_completed_step: row.last_completed_step || null,
    status: row.status,
    next_action: row.next_action || 'start',
    artifacts: row.artifacts || [],
    step_highlights: row.step_highlights || []
  }
} }];

const rows = $input.all();
const projects = rows.map(function(r) { return r.json; }).filter(function(r) { return r && r.project_id; });
return [{ json: { success: true, message: 'Projects loaded.', data: projects } }];
